{
  "name": "HxH 5e Heaven's Gate Terminal",
  "description": "A Hunter x Hunter 5e character sheet with AI-powered betting scenarios and Discord integration simulations."
}

export enum NenType {
  ENHANCEMENT = 'Enhancement',
  TRANSMUTATION = 'Transmutation',
  EMISSION = 'Emission',
  CONJURATION = 'Conjuration',
  MANIPULATION = 'Manipulation',
  SPECIALIZATION = 'Specialization',
}

export interface CharacterAttributes {
  strength: number;
  dexterity: number;
  constitution: number;
  intelligence: number;
  wisdom: number;
  charisma: number;
}

export interface Character {
  name: string;
  level: number;
  hunterStars: number;
  nenType: NenType;
  auraPoints: {
    current: number;
    max: number;
  };
  hitPoints: {
    current: number;
    max: number;
  };
  attributes: CharacterAttributes;
  jenny: number; // Currency
}

export interface BetScenario {
  id: string;
  title: string;
  description: string;
  difficulty: 'Easy' | 'Medium' | 'Hard' | 'Insane';
  winMultiplier: number; // e.g., 1.5x, 2.0x
  status: 'pending' | 'won' | 'lost';
}

export interface DiscordWebhookConfig {
  url: string;
  username: string;
  enabled: boolean;
}

import { NenType } from './types';

export const INITIAL_CHARACTER: any = {
  name: "Killua Z.",
  level: 5,
  hunterStars: 1,
  nenType: NenType.TRANSMUTATION,
  auraPoints: { current: 120, max: 150 },
  hitPoints: { current: 45, max: 45 },
  attributes: {
    strength: 14,
    dexterity: 18,
    constitution: 14,
    intelligence: 16,
    wisdom: 12,
    charisma: 13,
  },
  jenny: 5000000,
};

export const NEN_COLORS = {
  [NenType.ENHANCEMENT]: '#00ff41',
  [NenType.TRANSMUTATION]: '#a020f0',
  [NenType.EMISSION]: '#ffff00',
  [NenType.CONJURATION]: '#ff003c',
  [NenType.MANIPULATION]: '#00f0ff',
  [NenType.SPECIALIZATION]: '#ffffff',
};

import { GoogleGenAI, Type } from "@google/genai";
import { Character, BetScenario } from '../types';

// Ensure API Key is available
const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const generateBettingScenario = async (character: Character): Promise<BetScenario | null> => {
  if (!apiKey) {
    console.error("API Key missing");
    return null;
  }

  const model = "gemini-3-flash-preview";

  const prompt = `
    You are a Floor Master referee at Heaven's Arena in the Hunter x Hunter universe.
    Create a short, exciting betting scenario (a mini-challenge) for the following character:

    Name: ${character.name}
    Nen Type: ${character.nenType}
    Level: ${character.level}

    The scenario should be a quick check of their abilities (e.g., "Dodge a card thrown by Hisoka", "Arm wrestle a Chimera Ant", "Detect a concealed aura").

    Based on their stats (Level ${character.level}), assign a Difficulty and a Win Multiplier (Odds). 
    Harder tasks have higher multipliers.

    Return purely JSON.
  `;

  try {
    const response = await ai.models.generateContent({
      model,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            description: { type: Type.STRING },
            difficulty: { type: Type.STRING, enum: ["Easy", "Medium", "Hard", "Insane"] },
            winMultiplier: { type: Type.NUMBER, description: "Decimal number, e.g., 1.5, 2.0, 5.0" },
          },
          required: ["title", "description", "difficulty", "winMultiplier"]
        }
      }
    });

    if (response.text) {
      const data = JSON.parse(response.text);
      return {
        id: crypto.randomUUID(),
        title: data.title,
        description: data.description,
        difficulty: data.difficulty,
        winMultiplier: data.winMultiplier,
        status: 'pending'
      };
    }
  } catch (error) {
    console.error("Gemini Scenario Gen Error:", error);
  }
  return null;
};

export const resolveBetResult = async (character: Character, scenario: BetScenario): Promise<boolean> => {
   if (!apiKey) return Math.random() > 0.5; // Fallback if no key

   const model = "gemini-3-flash-preview";
   const prompt = `
     The character ${character.name} (Level ${character.level}, ${character.nenType}) is attempting: "${scenario.description}".
     Difficulty: ${scenario.difficulty}.

     Decide if they succeed or fail based on standard RPG logic and some randomness. 
     Return JSON with a boolean 'success' and a short 'narrative' explaining the outcome.
   `;

   try {
     const response = await ai.models.generateContent({
       model,
       contents: prompt,
       config: {
         responseMimeType: "application/json",
         responseSchema: {
           type: Type.OBJECT,
           properties: {
             success: { type: Type.BOOLEAN },
             narrative: { type: Type.STRING }
           }
         }
       }
     });

     if (response.text) {
        const data = JSON.parse(response.text);
        // We could display the narrative, but for now we just return the boolean state
        console.log("Narrative Result:", data.narrative);
        return data.success;
     }
   } catch (e) {
     console.error(e);
   }

   return Math.random() > 0.5;
};

import React, { useState, useEffect } from 'react';
import { Character, BetScenario, DiscordWebhookConfig } from '../types';
import { generateBettingScenario, resolveBetResult } from '../services/geminiService';
import { Trophy, Share2, AlertCircle, RefreshCw, Send, DollarSign, Activity } from 'lucide-react';
import { AreaChart, Area, XAxis, YAxis, Tooltip, ResponsiveContainer } from 'recharts';

interface Props {
  character: Character;
  onUpdateJenny: (amount: number) => void;
}

// Mock data for the "Market Trend" chart
const INITIAL_CHART_DATA = [
  { time: '10:00', value: 5000000 },
  { time: '10:05', value: 5100000 },
  { time: '10:10', value: 4950000 },
  { time: '10:15', value: 5200000 },
  { time: '10:20', value: 5350000 },
];

export const BettingTerminal: React.FC<Props> = ({ character, onUpdateJenny }) => {
  const [activeScenario, setActiveScenario] = useState<BetScenario | null>(null);
  const [loading, setLoading] = useState(false);
  const [wager, setWager] = useState<number>(1000);
  const [betStatus, setBetStatus] = useState<'idle' | 'placed' | 'resolving' | 'completed'>('idle');
  const [lastResult, setLastResult] = useState<'win' | 'loss' | null>(null);

  // Discord Config State
  const [discordConfig, setDiscordConfig] = useState<DiscordWebhookConfig>({
    url: '',
    username: 'Heaven\'s Arena Bookie',
    enabled: false
  });
  const [showConfig, setShowConfig] = useState(false);

  // Chart State
  const [chartData, setChartData] = useState(INITIAL_CHART_DATA);

  useEffect(() => {
      const savedConfig = localStorage.getItem('hxh_discord_config');
      if (savedConfig) {
          setDiscordConfig(JSON.parse(savedConfig));
      }
  }, []);

  const handleGenerateScenario = async () => {
    setLoading(true);
    setBetStatus('idle');
    setLastResult(null);
    const scenario = await generateBettingScenario(character);
    setActiveScenario(scenario);
    setLoading(false);
  };

  const saveDiscordConfig = () => {
      localStorage.setItem('hxh_discord_config', JSON.stringify(discordConfig));
      setShowConfig(false);
  };

  const sendToDiscord = async (won: boolean, profit: number, scenarioTitle: string) => {
    if (!discordConfig.enabled || !discordConfig.url) return;

    const content = {
      username: discordConfig.username,
      avatar_url: "https://i.imgur.com/8QWqXgq.png", // Generic HxH icon
      embeds: [{
        title: won ? "🎰 BIG WIN @ HEAVEN'S ARENA!" : "💀 BET LOST",
        description: won 
            ? `${character.name} just won **${profit.toLocaleString()} J** betting on "${scenarioTitle}"!`
            : `${character.name} lost **${wager.toLocaleString()} J** on "${scenarioTitle}". Better luck next time.`,
        color: won ? 5763719 : 15548997, // Green or Red
        fields: [
            { name: "Current Balance", value: `${(character.jenny + (won ? profit : -wager)).toLocaleString()} J`, inline: true },
            { name: "Odds", value: `${activeScenario?.winMultiplier}x`, inline: true }
        ],
        footer: { text: "HxH 5e System • Heaven's Gate Terminal" },
        timestamp: new Date().toISOString()
      }]
    };

    try {
      await fetch(discordConfig.url, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(content)
      });
    } catch (e) {
      console.error("Discord Webhook failed (likely CORS). This is expected in client-side only demos.", e);
      // In a real app, this would go through a proxy server. 
    }
  };

  const placeBet = async () => {
    if (!activeScenario) return;
    if (wager > character.jenny) {
        alert("Not enough Jenny!");
        return;
    }

    setBetStatus('resolving');

    // Artificial delay for suspense
    await new Promise(r => setTimeout(r, 1500));

    const won = await resolveBetResult(character, activeScenario);

    let profit = 0;
    if (won) {
        profit = Math.floor(wager * activeScenario.winMultiplier);
        onUpdateJenny(character.jenny + profit);
        setLastResult('win');

        // Update Chart
        const now = new Date();
        const timeString = `${now.getHours()}:${now.getMinutes().toString().padStart(2, '0')}`;
        setChartData(prev => [...prev.slice(-10), { time: timeString, value: character.jenny + profit }]);

    } else {
        onUpdateJenny(character.jenny - wager);
        setLastResult('loss');

        // Update Chart
        const now = new Date();
        const timeString = `${now.getHours()}:${now.getMinutes().toString().padStart(2, '0')}`;
        setChartData(prev => [...prev.slice(-10), { time: timeString, value: character.jenny - wager }]);
    }

    setBetStatus('completed');
    sendToDiscord(won, profit, activeScenario.title);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 p-6">

      {/* Left Column: Stats & Config */}
      <div className="lg:col-span-1 space-y-6">
        {/* Balance Card */}
        <div className="bg-hxh-panel border border-hxh-green/30 p-6 rounded-lg shadow-[0_0_15px_rgba(0,255,65,0.1)]">
            <h2 className="text-gray-400 text-sm uppercase font-bold tracking-widest mb-2 flex items-center gap-2">
                <DollarSign size={16} /> Account Balance
            </h2>
            <div className="text-4xl font-display font-bold text-white tracking-widest text-shadow-green">
                {character.jenny.toLocaleString()} <span className="text-hxh-green text-xl">J</span>
            </div>

            <div className="mt-6 h-32 w-full">
                 <ResponsiveContainer width="100%" height="100%">
                    <AreaChart data={chartData}>
                    <defs>
                        <linearGradient id="colorValue" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#00ff41" stopOpacity={0.3}/>
                        <stop offset="95%" stopColor="#00ff41" stopOpacity={0}/>
                        </linearGradient>
                    </defs>
                    <XAxis dataKey="time" hide />
                    <YAxis hide domain={['auto', 'auto']} />
                    <Tooltip 
                        contentStyle={{ backgroundColor: '#111', borderColor: '#333' }}
                        itemStyle={{ color: '#00ff41' }}
                    />
                    <Area type="monotone" dataKey="value" stroke="#00ff41" fillOpacity={1} fill="url(#colorValue)" />
                    </AreaChart>
                </ResponsiveContainer>
            </div>
        </div>

        {/* Discord Toggle */}
        <div className="bg-gray-900 border border-gray-800 p-4 rounded-lg">
            <div className="flex justify-between items-center mb-2">
                <h3 className="text-white font-bold flex items-center gap-2">
                    <Share2 size={16} className="text-[#5865F2]" /> Discord Integration
                </h3>
                <button 
                    onClick={() => setShowConfig(!showConfig)}
                    className="text-xs bg-gray-800 hover:bg-gray-700 px-2 py-1 rounded text-gray-300 transition"
                >
                    {showConfig ? 'Hide' : 'Configure'}
                </button>
            </div>

            <div className="flex items-center gap-2 text-sm">
                <div className={`w-2 h-2 rounded-full ${discordConfig.enabled ? 'bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.8)]' : 'bg-red-500'}`} />
                <span className="text-gray-400">{discordConfig.enabled ? 'Connected' : 'Disconnected'}</span>
            </div>

            {showConfig && (
                <div className="mt-4 space-y-3 animate-fade-in">
                    <input 
                        type="text" 
                        placeholder="Webhook URL" 
                        value={discordConfig.url}
                        onChange={(e) => setDiscordConfig({...discordConfig, url: e.target.value})}
                        className="w-full bg-black border border-gray-700 rounded p-2 text-xs text-white focus:border-[#5865F2] outline-none"
                    />
                     <input 
                        type="text" 
                        placeholder="Bot Username" 
                        value={discordConfig.username}
                        onChange={(e) => setDiscordConfig({...discordConfig, username: e.target.value})}
                        className="w-full bg-black border border-gray-700 rounded p-2 text-xs text-white focus:border-[#5865F2] outline-none"
                    />
                    <div className="flex items-center gap-2">
                        <input 
                            type="checkbox" 
                            id="enableDiscord"
                            checked={discordConfig.enabled}
                            onChange={(e) => setDiscordConfig({...discordConfig, enabled: e.target.checked})}
                            className="accent-[#5865F2]"
                        />
                        <label htmlFor="enableDiscord" className="text-xs text-gray-300">Enable Webhook</label>
                    </div>
                    <button 
                        onClick={saveDiscordConfig}
                        className="w-full bg-[#5865F2] hover:bg-[#4752C4] text-white text-xs font-bold py-2 rounded transition"
                    >
                        Save Configuration
                    </button>
                    <p className="text-[10px] text-gray-500 mt-1">
                        *Note: Client-side webhooks may be blocked by CORS without a proxy. This is a frontend demo.
                    </p>
                </div>
            )}
        </div>
      </div>

      {/* Center/Right: The Betting Terminal */}
      <div className="lg:col-span-2 flex flex-col h-full">
         <div className="flex-1 bg-black border-2 border-gray-800 relative rounded-xl overflow-hidden flex flex-col">

            {/* Terminal Header */}
            <div className="bg-gray-900 p-3 border-b border-gray-800 flex justify-between items-center">
                <span className="text-hxh-green font-display text-sm tracking-wider flex items-center gap-2">
                    <Activity size={16} /> LIVE BETTING FEED
                </span>
                <span className="text-gray-600 text-xs font-mono">ID: {activeScenario?.id.slice(0,8) || 'WAITING...'}</span>
            </div>

            {/* Main Content Area */}
            <div className="flex-1 p-8 flex flex-col items-center justify-center relative">
                {!activeScenario ? (
                    <div className="text-center space-y-4">
                        <Trophy size={64} className="text-gray-800 mx-auto" />
                        <h3 className="text-gray-500 font-display">No Active Scenario</h3>
                        <button 
                            onClick={handleGenerateScenario}
                            disabled={loading}
                            className="group relative px-6 py-3 bg-gray-900 border border-hxh-green text-hxh-green font-bold uppercase tracking-widest hover:bg-hxh-green hover:text-black transition-all duration-300 clip-path-polygon"
                        >
                            {loading ? 'Analyzing...' : 'Find New Match'}
                            <span className="absolute -bottom-1 -right-1 w-3 h-3 border-r-2 border-b-2 border-hxh-green opacity-50 group-hover:opacity-100 transition-opacity" />
                            <span className="absolute -top-1 -left-1 w-3 h-3 border-l-2 border-t-2 border-hxh-green opacity-50 group-hover:opacity-100 transition-opacity" />
                        </button>
                    </div>
                ) : (
                    <div className="w-full max-w-lg space-y-6 animate-fade-in-up">
                        <div className="flex justify-between items-start">
                            <span className={`px-2 py-1 text-xs font-bold rounded uppercase 
                                ${activeScenario.difficulty === 'Easy' ? 'bg-green-900 text-green-300' : 
                                  activeScenario.difficulty === 'Medium' ? 'bg-yellow-900 text-yellow-300' : 
                                  'bg-red-900 text-red-300'}`}>
                                {activeScenario.difficulty} Class
                            </span>
                            <div className="text-right">
                                <span className="block text-xs text-gray-500 uppercase">Multiplier</span>
                                <span className="text-2xl font-display font-bold text-hxh-accent">{activeScenario.winMultiplier}x</span>
                            </div>
                        </div>

                        <h2 className="text-2xl font-bold text-white leading-tight border-l-4 border-hxh-green pl-4">
                            {activeScenario.title}
                        </h2>
                        <p className="text-gray-400 font-mono text-sm bg-gray-900/50 p-4 rounded border border-gray-800">
                            {activeScenario.description}
                        </p>

                        {betStatus === 'idle' && (
                             <div className="space-y-4 pt-4 border-t border-gray-800">
                                <div className="flex justify-between text-sm text-gray-400">
                                    <span>Wager Amount</span>
                                    <span>Potential Win: <span className="text-hxh-green font-bold">{Math.floor(wager * activeScenario.winMultiplier).toLocaleString()} J</span></span>
                                </div>
                                <input 
                                    type="range" 
                                    min="1000" 
                                    max={character.jenny} 
                                    step="1000"
                                    value={wager}
                                    onChange={(e) => setWager(Number(e.target.value))}
                                    className="w-full h-2 bg-gray-800 rounded-lg appearance-none cursor-pointer accent-hxh-green"
                                />
                                <div className="flex justify-between items-center">
                                     <div className="bg-black border border-gray-700 px-3 py-1 text-white font-mono rounded">
                                        {wager.toLocaleString()} J
                                     </div>
                                     <div className="flex gap-2">
                                        <button 
                                            onClick={handleGenerateScenario}
                                            className="p-3 rounded-full border border-gray-700 text-gray-500 hover:text-white hover:border-white transition"
                                            title="Skip Scenario"
                                        >
                                            <RefreshCw size={20} />
                                        </button>
                                        <button 
                                            onClick={placeBet}
                                            className="flex items-center gap-2 bg-hxh-green text-black px-6 py-2 font-bold uppercase tracking-wider hover:bg-white transition-colors shadow-[0_0_15px_rgba(0,255,65,0.4)]"
                                        >
                                            Place Bet <Send size={16} />
                                        </button>
                                     </div>
                                </div>
                             </div>
                        )}

                        {betStatus === 'resolving' && (
                            <div className="flex flex-col items-center justify-center py-8 space-y-4">
                                <div className="w-12 h-12 border-4 border-hxh-green border-t-transparent rounded-full animate-spin" />
                                <p className="text-hxh-green animate-pulse font-display tracking-widest">AWAITING REFEREE DECISION...</p>
                            </div>
                        )}

                        {betStatus === 'completed' && lastResult && (
                            <div className={`p-6 text-center border-2 ${lastResult === 'win' ? 'border-hxh-green bg-green-900/10' : 'border-red-600 bg-red-900/10'} rounded-lg animate-scale-in`}>
                                <h3 className={`text-3xl font-display font-bold ${lastResult === 'win' ? 'text-hxh-green' : 'text-red-500'} mb-2`}>
                                    {lastResult === 'win' ? 'BET WON' : 'BET LOST'}
                                </h3>
                                <p className="text-gray-300">
                                    {lastResult === 'win' 
                                        ? `Congratulations! You gained ${Math.floor(wager * activeScenario.winMultiplier).toLocaleString()} Jenny.`
                                        : `You lost ${wager.toLocaleString()} Jenny. Better luck next time.`
                                    }
                                </p>
                                <button 
                                    onClick={handleGenerateScenario}
                                    className="mt-6 text-sm text-gray-400 underline hover:text-white"
                                >
                                    Find New Match
                                </button>
                            </div>
                        )}
                    </div>
                )}
            </div>

             {/* Footer Status Line */}
             <div className="bg-gray-900 p-2 text-[10px] text-gray-500 flex justify-between font-mono">
                <span>SERVER: HEAVEN_NET_04</span>
                <span>PING: 24ms</span>
                <span>STATUS: ONLINE</span>
            </div>
         </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { INITIAL_CHARACTER } from './constants';
import { Character } from './types';
import { CharacterHeader } from './components/CharacterHeader';
import { BettingTerminal } from './components/BettingTerminal';
import { Users, Activity, Hexagon } from 'lucide-react';
import { Radar, RadarChart, PolarGrid, PolarAngleAxis, ResponsiveContainer } from 'recharts';

function App() {
  const [character, setCharacter] = useState<Character>(INITIAL_CHARACTER);
  const [activeTab, setActiveTab] = useState<'stats' | 'abilities' | 'betting'>('betting');

  const updateJenny = (newAmount: number) => {
    setCharacter(prev => ({ ...prev, jenny: newAmount }));
  };

  const attributesData = [
    { subject: 'STR', A: character.attributes.strength, fullMark: 20 },
    { subject: 'DEX', A: character.attributes.dexterity, fullMark: 20 },
    { subject: 'CON', A: character.attributes.constitution, fullMark: 20 },
    { subject: 'INT', A: character.attributes.intelligence, fullMark: 20 },
    { subject: 'WIS', A: character.attributes.wisdom, fullMark: 20 },
    { subject: 'CHA', A: character.attributes.charisma, fullMark: 20 },
  ];

  return (
    <div className="min-h-screen pb-20 bg-[#050505] text-gray-200 selection:bg-hxh-green selection:text-black">
      <CharacterHeader character={character} />

      <main className="max-w-7xl mx-auto mt-6 px-4">
        {/* Navigation Tabs */}
        <div className="flex border-b border-gray-800 mb-6">
            <button 
                onClick={() => setActiveTab('stats')}
                className={`flex items-center gap-2 px-6 py-3 font-display font-bold tracking-wider transition-colors border-b-2 
                ${activeTab === 'stats' ? 'border-hxh-green text-white' : 'border-transparent text-gray-600 hover:text-gray-400'}`}
            >
                <Hexagon size={18} /> STATUS
            </button>
             <button 
                onClick={() => setActiveTab('abilities')}
                className={`flex items-center gap-2 px-6 py-3 font-display font-bold tracking-wider transition-colors border-b-2 
                ${activeTab === 'abilities' ? 'border-hxh-green text-white' : 'border-transparent text-gray-600 hover:text-gray-400'}`}
            >
                <Users size={18} /> HATSU
            </button>
             <button 
                onClick={() => setActiveTab('betting')}
                className={`flex items-center gap-2 px-6 py-3 font-display font-bold tracking-wider transition-colors border-b-2 
                ${activeTab === 'betting' ? 'border-hxh-green text-white' : 'border-transparent text-gray-600 hover:text-gray-400'}`}
            >
                <Activity size={18} /> HEAVEN'S BET
            </button>
        </div>

        {/* Tab Content */}
        <div className="animate-fade-in">
            {activeTab === 'betting' && (
                <BettingTerminal character={character} onUpdateJenny={updateJenny} />
            )}

            {activeTab === 'stats' && (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-8 p-6">
                    <div className="bg-hxh-panel border border-gray-800 p-8 rounded-lg flex items-center justify-center">
                         <div className="h-80 w-full">
                            <ResponsiveContainer width="100%" height="100%">
                                <RadarChart cx="50%" cy="50%" outerRadius="80%" data={attributesData}>
                                <PolarGrid stroke="#333" />
                                <PolarAngleAxis dataKey="subject" tick={{ fill: '#666', fontSize: 12 }} />
                                <Radar
                                    name="Attributes"
                                    dataKey="A"
                                    stroke="#00ff41"
                                    strokeWidth={2}
                                    fill="#00ff41"
                                    fillOpacity={0.3}
                                />
                                </RadarChart>
                            </ResponsiveContainer>
                         </div>
                    </div>
                    <div className="space-y-4">
                        <h3 className="text-xl font-display text-white border-l-4 border-hxh-blue pl-3">Hunter License Info</h3>
                        <p className="text-gray-400 text-sm leading-relaxed">
                            This Hunter License grants the holder the right to access restricted areas, use public facilities for free, and carry over 95% of standard value as credit in Heaven's Arena betting terminals.
                            <br /><br />
                            <strong>Current Rank:</strong> Floor Master Candidate
                            <br />
                            <strong>Nen Affinity:</strong> {character.nenType}
                        </p>
                    </div>
                </div>
            )}

            {activeTab === 'abilities' && (
                <div className="p-12 text-center text-gray-500 border border-dashed border-gray-800 rounded-lg">
                    <h2 className="text-2xl font-display text-white mb-2">Hatsu Registry</h2>
                    <p>Access restricted. Please authenticate with Hunter License to view hidden techniques.</p>
                </div>
            )}
        </div>
      </main>
    </div>
  );
}

