  onUpdateJenny: (amount: number) => void;
}

// Initial Mock Match
const DEFAULT_MATCH: LiveMatch = {
  id: 'match_200f_01',
  floor: 200,
  status: 'OPEN',
  fighterA: {
    id: 'f1',
    name: 'Hisoka Morrow',
    imageUrl: 'https://i.pinimg.com/736x/2c/11/2b/2c112b4b45533166d4b6555db6cb8834.jpg',
    totalPool: 1500000
  },
  fighterB: {
    id: 'f2',
    name: 'Gon Freecss',
