    totalPool: 800000
  }
};

export const BettingTerminal: React.FC<Props> = ({ character, onUpdateJenny }) => {
  // State
  const [match, setMatch] = useState<LiveMatch>(DEFAULT_MATCH);
  const [wager, setWager] = useState<number>(1000);
  const [selectedFighterId, setSelectedFighterId] = useState<string | null>(null);
  const [isSetupOpen, setIsSetupOpen] = useState(false);

  // Discord Config State
  const [discordConfig, setDiscordConfig] = useState<DiscordWebhookConfig>({
    url: '',
    username: 'Heaven\'s Arena Bookie',
    enabled: false
  });
  const [showConfig, setShowConfig] = useState(false);

  // Setup inputs
  const [setupData, setSetupData] = useState({
      nameA: DEFAULT_MATCH.fighterA.name,
      imgA: DEFAULT_MATCH.fighterA.imageUrl,
      nameB: DEFAULT_MATCH.fighterB.name,
      imgB: DEFAULT_MATCH.fighterB.imageUrl
  });

  // Calculate Odds (Decimal Odds)
  // Formula: Total Pool / Fighter Pool. House take is ignored for simplicity or can be added (e.g. * 0.95)
  const totalPool = match.fighterA.totalPool + match.fighterB.totalPool;
  const oddsA = totalPool > 0 ? (totalPool / Math.max(match.fighterA.totalPool, 1)) : 2.0;
  const oddsB = totalPool > 0 ? (totalPool / Math.max(match.fighterB.totalPool, 1)) : 2.0;

  useEffect(() => {
      const savedConfig = localStorage.getItem('hxh_discord_config');
      if (savedConfig) {
          setDiscordConfig(JSON.parse(savedConfig));
      }
  }, []);

  // Simulate Live Betting (The "Hype" Factor)
  // This effect randomly increases the pools to simulate other Discord users betting
  useEffect(() => {
    if (match.status !== 'OPEN') return;

    const interval = setInterval(() => {
        setMatch(prev => {
            // Randomly add bets to A or B
            const addToA = Math.random() > 0.4 ? Math.floor(Math.random() * 50000) : 0;
            const addToB = Math.random() > 0.4 ? Math.floor(Math.random() * 50000) : 0;

            return {
                ...prev,
                fighterA: { ...prev.fighterA, totalPool: prev.fighterA.totalPool + addToA },
                fighterB: { ...prev.fighterB, totalPool: prev.fighterB.totalPool + addToB }
            };
        });
    }, 2000);

    return () => clearInterval(interval);
  }, [match.status]);

  const saveDiscordConfig = () => {
      localStorage.setItem('hxh_discord_config', JSON.stringify(discordConfig));
      setShowConfig(false);
  };

  const updateMatchSetup = () => {
      setMatch(prev => ({
          ...prev,
          fighterA: { ...prev.fighterA, name: setupData.nameA, imageUrl: setupData.imgA, totalPool: 100000 },
          fighterB: { ...prev.fighterB, name: setupData.nameB, imageUrl: setupData.imgB, totalPool: 100000 },
          status: 'OPEN'
      }));
      setIsSetupOpen(false);
  };

  const sendToDiscord = async (fighterName: string, odds: number) => {
    if (!discordConfig.enabled || !discordConfig.url) return;

    const content = {
      username: discordConfig.username,
      avatar_url: "https://i.imgur.com/8QWqXgq.png", 
      embeds: [{
        title: "🎟️ TICKET CONFIRMED",
        description: `A new bet has been placed on the **${match.floor}th Floor** match!`,
        color: 5763719, // Green
        thumbnail: { url: selectedFighterId === match.fighterA.id ? match.fighterA.imageUrl : match.fighterB.imageUrl },
        fields: [
            { name: "Bettor", value: character.name, inline: true },
            { name: "Fighter", value: fighterName, inline: true },
            { name: "Wager", value: `${wager.toLocaleString()} J`, inline: true },
            { name: "Locked Odds", value: `${odds.toFixed(2)}x`, inline: true },
            { name: "Potential Payout", value: `${Math.floor(wager * odds).toLocaleString()} J`, inline: false },
        ],
        footer: { text: `Total Pool: ${totalPool.toLocaleString()} J` },
        timestamp: new Date().toISOString()
      }]
    };

    try {
      await fetch(discordConfig.url, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(content)
      });
    } catch (e) {
      console.error("Discord Webhook failed (likely CORS). This is expected in client-side only demos.", e);
    }
  };

  const handlePlaceBet = () => {
      if (wager > character.jenny) {
          alert("Insufficient funds!");
          return;
      }
      if (!selectedFighterId) return;

      const isA = selectedFighterId === match.fighterA.id;
      const currentOdds = isA ? oddsA : oddsB;
      const fighterName = isA ? match.fighterA.name : match.fighterB.name;

      // Deduct funds
      onUpdateJenny(character.jenny - wager);

      // Add to pool locally
      setMatch(prev => ({
          ...prev,
          fighterA: { ...prev.fighterA, totalPool: prev.fighterA.totalPool + (isA ? wager : 0) },
          fighterB: { ...prev.fighterB, totalPool: prev.fighterB.totalPool + (!isA ? wager : 0) },
      }));

      // Send webhook
      sendToDiscord(fighterName, currentOdds);

      alert(`Bet placed on ${fighterName}!`);
      setSelectedFighterId(null);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-4 gap-6 p-4 md:p-6 h-full">

