             >
                 <span className="flex items-center gap-2"><Settings size={14}/> Match Setup (GM)</span>
                 <span>{isSetupOpen ? '−' : '+'}</span>
             </button>

             {isSetupOpen && (
                 <div className="p-4 space-y-3 bg-black border-t border-gray-800 animate-fade-in">
                     <div className="space-y-1">
                        <label className="text-[10px] text-gray-500 uppercase">Fighter A Name</label>
                        <input type="text" value={setupData.nameA} onChange={e => setSetupData({...setupData, nameA: e.target.value})} className="w-full bg-gray-900 border border-gray-700 text-xs text-white p-2 rounded focus:border-hxh-green outline-none" />
                     </div>
                     <div className="space-y-1">
                        <label className="text-[10px] text-gray-500 uppercase">Fighter A Image URL</label>
                        <input type="text" value={setupData.imgA} onChange={e => setSetupData({...setupData, imgA: e.target.value})} className="w-full bg-gray-900 border border-gray-700 text-xs text-white p-2 rounded focus:border-hxh-green outline-none" />
                     </div>
                     <div className="w-full h-px bg-gray-800 my-2" />
                     <div className="space-y-1">
                        <label className="text-[10px] text-gray-500 uppercase">Fighter B Name</label>
                        <input type="text" value={setupData.nameB} onChange={e => setSetupData({...setupData, nameB: e.target.value})} className="w-full bg-gray-900 border border-gray-700 text-xs text-white p-2 rounded focus:border-hxh-green outline-none" />
                     </div>
                     <div className="space-y-1">
                        <label className="text-[10px] text-gray-500 uppercase">Fighter B Image URL</label>
                        <input type="text" value={setupData.imgB} onChange={e => setSetupData({...setupData, imgB: e.target.value})} className="w-full bg-gray-900 border border-gray-700 text-xs text-white p-2 rounded focus:border-hxh-green outline-none" />
                     </div>
                     <button onClick={updateMatchSetup} className="w-full bg-hxh-green text-black font-bold text-xs py-2 rounded mt-2 uppercase">
                         Start New Match
                     </button>
                 </div>
             )}
        </div>

        {/* Discord Config */}
        <div className="bg-gray-900 border border-gray-800 p-4 rounded-lg">
            <div className="flex justify-between items-center mb-2">
                <h3 className="text-white font-bold flex items-center gap-2 text-xs">
