                </h3>
                <button onClick={() => setShowConfig(!showConfig)} className="text-[10px] bg-gray-800 hover:bg-gray-700 px-2 py-1 rounded text-gray-300 transition">
                    Config
                </button>
            </div>
            {showConfig && (
                <div className="mt-2 space-y-2 animate-fade-in">
                    <input type="text" placeholder="Webhook URL" value={discordConfig.url} onChange={(e) => setDiscordConfig({...discordConfig, url: e.target.value})} className="w-full bg-black border border-gray-700 rounded p-2 text-[10px] text-white outline-none" />
                    <div className="flex items-center gap-2">
                        <input type="checkbox" checked={discordConfig.enabled} onChange={(e) => setDiscordConfig({...discordConfig, enabled: e.target.checked})} className="accent-[#5865F2]" />
