                    <button onClick={saveDiscordConfig} className="w-full bg-[#5865F2] text-white text-[10px] font-bold py-1 rounded">Save</button>
                </div>
            )}
        </div>
      </div>

      {/* CENTER/RIGHT: The Matchup UI */}
      <div className="lg:col-span-3 flex flex-col h-full bg-black border-2 border-gray-800 rounded-xl overflow-hidden relative">

         {/* Live Header */}
