  const sendToDiscord = async (fighterName: string, odds: number) => {
    if (!discordConfig.enabled || !discordConfig.url) return;

    const content = {
      username: discordConfig.username,
      avatar_url: "https://i.imgur.com/8QWqXgq.png", 
      embeds: [{
        title: "🎟️ TICKET CONFIRMED",
        description: `A new bet has been placed on the **${match.floor}th Floor** match!`,
        color: 5763719, 
        thumbnail: { url: selectedFighterId === match.fighterA.id ? match.fighterA.imageUrl : match.fighterB.imageUrl },
