        {/* Wallet */}
        <div className="bg-hxh-panel border border-hxh-green/30 p-6 rounded-lg shadow-[0_0_15px_rgba(0,255,65,0.1)] relative overflow-hidden">
            <div className="absolute top-0 right-0 p-4 opacity-10">
                <DollarSign size={100} />
            </div>
            <h2 className="text-gray-400 text-xs uppercase font-bold tracking-widest mb-2 flex items-center gap-2">
                Available Balance
            </h2>
            <div className="text-4xl font-display font-bold text-white tracking-widest text-shadow-green break-all">
                {character.jenny.toLocaleString()} <span className="text-hxh-green text-lg">J</span>
            </div>
        </div>

        {/* History Graph */}
        <div className="bg-gray-900 border border-gray-800 rounded-lg p-4 flex-1 flex flex-col">
            <h3 className="text-white font-display text-sm mb-4 border-l-4 border-hxh-green pl-2 uppercase tracking-wider">
                Betting Performance
            </h3>
            <div className="flex-1 min-h-[250px] w-full">
                <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={chartData} margin={{ top: 5, right: 0, left: -20, bottom: 0 }}>
                        <XAxis dataKey="name" tick={{ fontSize: 10, fill: '#666' }} interval={0} />
                        <YAxis tick={{ fontSize: 10, fill: '#666' }} />
                        <Tooltip 
                            contentStyle={{ backgroundColor: '#111', borderColor: '#333' }}
                            itemStyle={{ color: '#fff' }}
                            cursor={{fill: 'rgba(255,255,255,0.05)'}}
                        />
                        <Bar dataKey="amount">
                        {chartData.map((entry, index) => (
                            <Cell key={`cell-${index}`} fill={entry.result === 'WIN' ? '#00ff41' : '#ff003c'} fillOpacity={0.8} />
                        ))}
                        </Bar>
                    </BarChart>
                </ResponsiveContainer>
            </div>
            <div className="mt-4 grid grid-cols-2 gap-2 text-xs text-center">
                 <div className="bg-green-900/20 p-2 rounded border border-green-900/50">
                    <span className="block text-green-500 font-bold flex justify-center items-center gap-1"><TrendingUp size={12}/> WINS</span>
                    <span className="text-white">{character.bettingHistory.filter(b => b.result === 'WIN').length}</span>
                 </div>
                 <div className="bg-red-900/20 p-2 rounded border border-red-900/50">
                    <span className="block text-red-500 font-bold flex justify-center items-center gap-1"><TrendingDown size={12}/> LOSSES</span>
                    <span className="text-white">{character.bettingHistory.filter(b => b.result === 'LOSS').length}</span>
