import React, { useState } from 'react';
import { INITIAL_CHARACTER } from './constants';
import { Character } from './types';
import { CharacterHeader } from './components/CharacterHeader';
import { BettingTerminal } from './components/BettingTerminal'; // This is now Bettor Dashboard
import { CompetitorDashboard } from './components/CompetitorDashboard';
import { User, Dices } from 'lucide-react';

function App() {
  const [character, setCharacter] = useState<Character>(INITIAL_CHARACTER);
  const [mode, setMode] = useState<'BETTOR' | 'FIGHTER'>('BETTOR');

  const updateJenny = (newAmount: number) => {
    setCharacter(prev => ({ ...prev, jenny: newAmount }));
  };

  return (
    <div className="min-h-screen pb-20 bg-[#050505] text-gray-200 selection:bg-hxh-green selection:text-black font-body">
      <CharacterHeader character={character} />

      <main className="max-w-7xl mx-auto mt-6 px-4">

        {/* MODE SWITCHER */}
        <div className="flex justify-center mb-8">
            <div className="bg-gray-900 border border-gray-700 rounded-full p-1 flex relative">
                {/* Moving Background Pill */}
                <div 
                    className={`absolute top-1 bottom-1 w-[140px] bg-hxh-green rounded-full shadow-[0_0_15px_rgba(0,255,65,0.4)] transition-all duration-300 ease-in-out`}
                    style={{ left: mode === 'BETTOR' ? '4px' : '148px' }}
                />

                <button 
                    onClick={() => setMode('BETTOR')}
                    className={`relative z-10 w-[140px] py-2 flex items-center justify-center gap-2 font-display font-bold text-sm tracking-wider uppercase transition-colors duration-300 ${mode === 'BETTOR' ? 'text-black' : 'text-gray-500 hover:text-white'}`}
                >
                    <Dices size={16} /> Bettor
                </button>

                <button 
                    onClick={() => setMode('FIGHTER')}
                    className={`relative z-10 w-[140px] py-2 flex items-center justify-center gap-2 font-display font-bold text-sm tracking-wider uppercase transition-colors duration-300 ${mode === 'FIGHTER' ? 'text-black' : 'text-gray-500 hover:text-white'}`}
                >
                    <User size={16} /> Competitor
                </button>
            </div>
        </div>

        {/* Content Area */}
        <div className="animate-fade-in">
            {mode === 'BETTOR' ? (
                <BettingTerminal character={character} onUpdateJenny={updateJenny} />
            ) : (
                <CompetitorDashboard character={character} />
            )}
        </div>

      </main>
    </div>
  );
}

export default App;

import React, { useState, useEffect } from 'react';
import { Character, LiveMatch, DiscordWebhookConfig } from '../types';
import { Share2, Swords, DollarSign, Settings, Lock, Unlock, TrendingUp, TrendingDown } from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell } from 'recharts';

interface Props {
  character: Character;
  onUpdateJenny: (amount: number) => void;
}

// Initial Mock Match
const DEFAULT_MATCH: LiveMatch = {
  id: 'match_200f_01',
  floor: 200,
  status: 'OPEN',
  fighterA: {
    id: 'f1',
    name: 'Hisoka Morrow',
    imageUrl: 'https://i.pinimg.com/736x/2c/11/2b/2c112b4b45533166d4b6555db6cb8834.jpg',
    totalPool: 1500000
  },
  fighterB: {
    id: 'f2',
    name: 'Gon Freecss',
    imageUrl: 'https://i.pinimg.com/736x/56/67/74/566774c43147bf9081297534449833a6.jpg',
    totalPool: 800000
  }
};

export const BettingTerminal: React.FC<Props> = ({ character, onUpdateJenny }) => {
  // State
  const [match, setMatch] = useState<LiveMatch>(DEFAULT_MATCH);
  const [wager, setWager] = useState<number>(1000);
  const [selectedFighterId, setSelectedFighterId] = useState<string | null>(null);
  const [isSetupOpen, setIsSetupOpen] = useState(false);

  // Discord Config State
  const [discordConfig, setDiscordConfig] = useState<DiscordWebhookConfig>({
    url: '',
    username: 'Bookie da Torre Celestial',
    enabled: false
  });
  const [showConfig, setShowConfig] = useState(false);

  // Setup inputs
  const [setupData, setSetupData] = useState({
      nameA: DEFAULT_MATCH.fighterA.name,
      imgA: DEFAULT_MATCH.fighterA.imageUrl,
      nameB: DEFAULT_MATCH.fighterB.name,
      imgB: DEFAULT_MATCH.fighterB.imageUrl
  });

  const totalPool = match.fighterA.totalPool + match.fighterB.totalPool;
  const oddsA = totalPool > 0 ? (totalPool / Math.max(match.fighterA.totalPool, 1)) : 2.0;
  const oddsB = totalPool > 0 ? (totalPool / Math.max(match.fighterB.totalPool, 1)) : 2.0;

  useEffect(() => {
      const savedConfig = localStorage.getItem('hxh_discord_config');
      if (savedConfig) {
          setDiscordConfig(JSON.parse(savedConfig));
      }
  }, []);

  // Simulate Live Betting (The "Hype" Factor)
  useEffect(() => {
    if (match.status !== 'OPEN') return;

    const interval = setInterval(() => {
        setMatch(prev => {
            const addToA = Math.random() > 0.4 ? Math.floor(Math.random() * 50000) : 0;
            const addToB = Math.random() > 0.4 ? Math.floor(Math.random() * 50000) : 0;

            return {
                ...prev,
                fighterA: { ...prev.fighterA, totalPool: prev.fighterA.totalPool + addToA },
                fighterB: { ...prev.fighterB, totalPool: prev.fighterB.totalPool + addToB }
            };
        });
    }, 2000);

    return () => clearInterval(interval);
  }, [match.status]);

  const saveDiscordConfig = () => {
      localStorage.setItem('hxh_discord_config', JSON.stringify(discordConfig));
      setShowConfig(false);
  };

  const updateMatchSetup = () => {
      setMatch(prev => ({
          ...prev,
          fighterA: { ...prev.fighterA, name: setupData.nameA, imageUrl: setupData.imgA, totalPool: 100000 },
          fighterB: { ...prev.fighterB, name: setupData.nameB, imageUrl: setupData.imgB, totalPool: 100000 },
          status: 'OPEN'
      }));
      setIsSetupOpen(false);
  };

  const sendToDiscord = async (fighterName: string, odds: number) => {
    if (!discordConfig.enabled || !discordConfig.url) return;

    const content = {
      username: discordConfig.username,
      avatar_url: "https://i.imgur.com/8QWqXgq.png", 
      embeds: [{
        title: "🎟️ TICKET CONFIRMADO",
        description: `Uma nova aposta foi feita na batalha do **${match.floor}º Andar**!`,
        color: 5763719, 
        thumbnail: { url: selectedFighterId === match.fighterA.id ? match.fighterA.imageUrl : match.fighterB.imageUrl },
        fields: [
            { name: "Apostador", value: character.name, inline: true },
            { name: "Lutador", value: fighterName, inline: true },
            { name: "Valor", value: `${wager.toLocaleString()} J`, inline: true },
            { name: "Odds Travadas", value: `${odds.toFixed(2)}x`, inline: true },
        ],
        footer: { text: `Pool Total: ${totalPool.toLocaleString()} J` },
        timestamp: new Date().toISOString()
      }]
    };

    try {
      await fetch(discordConfig.url, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(content)
      });
    } catch (e) {
      console.error("Discord Webhook failed.", e);
    }
  };

  const handlePlaceBet = () => {
      if (wager > character.jenny) {
          alert("Fundos Insuficientes!");
          return;
      }
      if (!selectedFighterId) return;

      const isA = selectedFighterId === match.fighterA.id;
      const currentOdds = isA ? oddsA : oddsB;
      const fighterName = isA ? match.fighterA.name : match.fighterB.name;

      onUpdateJenny(character.jenny - wager);

      setMatch(prev => ({
          ...prev,
          fighterA: { ...prev.fighterA, totalPool: prev.fighterA.totalPool + (isA ? wager : 0) },
          fighterB: { ...prev.fighterB, totalPool: prev.fighterB.totalPool + (!isA ? wager : 0) },
      }));

      sendToDiscord(fighterName, currentOdds);
      alert(`Aposta realizada em ${fighterName}!`);
      setSelectedFighterId(null);
  };

  // Prepare Chart Data from History
  const chartData = character.bettingHistory.map(bet => ({
      name: bet.fighterName,
      amount: bet.amount,
      result: bet.result,
      profit: bet.result === 'WIN' ? bet.amount : -bet.amount
  }));

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 p-4 md:p-6 h-full animate-fade-in">

      {/* LEFT COLUMN: HISTORY & WALLET (4 cols) */}
      <div className="lg:col-span-4 space-y-6 flex flex-col">
        {/* Wallet */}
        <div className="bg-hxh-panel border border-hxh-green/30 p-6 rounded-lg shadow-[0_0_15px_rgba(0,255,65,0.1)] relative overflow-hidden">
            <div className="absolute top-0 right-0 p-4 opacity-10">
                <DollarSign size={100} />
            </div>
            <h2 className="text-gray-400 text-xs uppercase font-bold tracking-widest mb-2 flex items-center gap-2">
                Saldo Disponível
            </h2>
            <div className="text-4xl font-display font-bold text-white tracking-widest text-shadow-green break-all">
                {character.jenny.toLocaleString()} <span className="text-hxh-green text-lg">J</span>
            </div>
        </div>

        {/* History Graph */}
        <div className="bg-gray-900 border border-gray-800 rounded-lg p-4 flex-1 flex flex-col">
            <h3 className="text-white font-display text-sm mb-4 border-l-4 border-hxh-green pl-2 uppercase tracking-wider">
                Histórico de Apostas
            </h3>
            <div className="flex-1 min-h-[250px] w-full">
                <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={chartData} margin={{ top: 5, right: 0, left: -20, bottom: 0 }}>
                        <XAxis dataKey="name" tick={{ fontSize: 10, fill: '#666' }} interval={0} />
                        <YAxis tick={{ fontSize: 10, fill: '#666' }} />
                        <Tooltip 
                            contentStyle={{ backgroundColor: '#111', borderColor: '#333' }}
                            itemStyle={{ color: '#fff' }}
                            cursor={{fill: 'rgba(255,255,255,0.05)'}}
                            formatter={(value: number) => [`${value.toLocaleString()} J`, 'Valor']}
                        />
                        <Bar dataKey="amount">
                        {chartData.map((entry, index) => (
                            <Cell key={`cell-${index}`} fill={entry.result === 'WIN' ? '#00ff41' : '#ff003c'} fillOpacity={0.8} />
                        ))}
                        </Bar>
                    </BarChart>
                </ResponsiveContainer>
            </div>
            <div className="mt-4 grid grid-cols-2 gap-2 text-xs text-center">
                 <div className="bg-green-900/20 p-2 rounded border border-green-900/50">
                    <span className="block text-green-500 font-bold flex justify-center items-center gap-1"><TrendingUp size={12}/> VITÓRIAS</span>
                    <span className="text-white">{character.bettingHistory.filter(b => b.result === 'WIN').length}</span>
                 </div>
                 <div className="bg-red-900/20 p-2 rounded border border-red-900/50">
                    <span className="block text-red-500 font-bold flex justify-center items-center gap-1"><TrendingDown size={12}/> DERROTAS</span>
                    <span className="text-white">{character.bettingHistory.filter(b => b.result === 'LOSS').length}</span>
                 </div>
            </div>
        </div>

        {/* Configurations */}
         <div className="bg-gray-900 border border-gray-800 rounded-lg overflow-hidden">
             {/* Match Setup Toggle */}
             <button 
                onClick={() => setIsSetupOpen(!isSetupOpen)}
                className="w-full p-3 border-b border-gray-800 flex justify-between items-center text-[10px] font-bold uppercase tracking-wider text-gray-400 hover:text-white hover:bg-gray-800 transition"
             >
                 <span className="flex items-center gap-2"><Settings size={12}/> Config. GM</span>
                 <span>{isSetupOpen ? '−' : '+'}</span>
             </button>
             {isSetupOpen && (
                 <div className="p-3 space-y-2 bg-black animate-fade-in">
                     <input type="text" placeholder="Nome Lutador A" value={setupData.nameA} onChange={e => setSetupData({...setupData, nameA: e.target.value})} className="w-full bg-gray-900 border border-gray-700 text-xs text-white p-2 rounded" />
                     <input type="text" placeholder="Imagem Lutador A" value={setupData.imgA} onChange={e => setSetupData({...setupData, imgA: e.target.value})} className="w-full bg-gray-900 border border-gray-700 text-xs text-white p-2 rounded" />
                     <div className="w-full h-px bg-gray-800" />
                     <input type="text" placeholder="Nome Lutador B" value={setupData.nameB} onChange={e => setSetupData({...setupData, nameB: e.target.value})} className="w-full bg-gray-900 border border-gray-700 text-xs text-white p-2 rounded" />
                     <input type="text" placeholder="Imagem Lutador B" value={setupData.imgB} onChange={e => setSetupData({...setupData, imgB: e.target.value})} className="w-full bg-gray-900 border border-gray-700 text-xs text-white p-2 rounded" />
                     <button onClick={updateMatchSetup} className="w-full bg-hxh-green text-black font-bold text-xs py-2 rounded uppercase mt-2">NOVA LUTA</button>
                 </div>
             )}

             {/* Discord Toggle */}
             <button 
                onClick={() => setShowConfig(!showConfig)}
                className="w-full p-3 flex justify-between items-center text-[10px] font-bold uppercase tracking-wider text-gray-400 hover:text-white hover:bg-gray-800 transition"
             >
                 <span className="flex items-center gap-2"><Share2 size={12}/> Link Discord</span>
                 <div className={`w-2 h-2 rounded-full ${discordConfig.enabled ? 'bg-green-500' : 'bg-red-500'}`} />
             </button>
             {showConfig && (
                <div className="p-3 space-y-2 bg-black animate-fade-in">
                    <input type="text" placeholder="Webhook URL" value={discordConfig.url} onChange={(e) => setDiscordConfig({...discordConfig, url: e.target.value})} className="w-full bg-gray-900 border border-gray-700 rounded p-2 text-[10px] text-white" />
                    <label className="flex items-center gap-2 text-[10px] text-gray-400">
                        <input type="checkbox" checked={discordConfig.enabled} onChange={(e) => setDiscordConfig({...discordConfig, enabled: e.target.checked})} className="accent-[#5865F2]" /> Ativar Webhook
                    </label>
                    <button onClick={saveDiscordConfig} className="w-full bg-[#5865F2] text-white text-[10px] font-bold py-1 rounded">Salvar Config</button>
                </div>
            )}
        </div>
      </div>

      {/* RIGHT COLUMN: LIVE MATCH (8 cols) */}
      <div className="lg:col-span-8 flex flex-col h-full bg-black border-2 border-gray-800 rounded-xl overflow-hidden relative shadow-2xl">

         {/* Live Header */}
         <div className="absolute top-0 w-full z-20 flex justify-between items-start p-4 pointer-events-none">
             <div className="bg-red-600 text-white px-3 py-1 font-bold text-xs uppercase tracking-widest animate-pulse shadow-lg skew-x-[-10deg]">
                 AO VIVO • {match.floor}º ANDAR
             </div>
             <div className="bg-gray-900/80 backdrop-blur border border-gray-700 text-gray-300 px-3 py-1 font-mono text-xs rounded">
                 POOL: <span className="text-hxh-green font-bold">{totalPool.toLocaleString()} J</span>
             </div>
         </div>

         {/* VS Background Split */}
         <div className="flex-1 flex flex-col md:flex-row relative">

             {/* FIGHTER A */}
             <div 
                className={`flex-1 relative group cursor-pointer border-r border-gray-800 transition-all duration-500 overflow-hidden
                ${selectedFighterId === match.fighterA.id ? 'flex-[1.5] brightness-110' : 'flex-1 brightness-75 hover:brightness-100'}
                ${selectedFighterId && selectedFighterId !== match.fighterA.id ? 'grayscale opacity-50' : ''}
                `}
                onClick={() => setSelectedFighterId(match.fighterA.id)}
             >
                 <div className="absolute inset-0 bg-cover bg-center transition-transform duration-700 group-hover:scale-105" style={{ backgroundImage: `url(${match.fighterA.imageUrl})` }} />
                 <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-black/60" />

                 <div className="absolute bottom-0 w-full p-6 bg-gradient-to-t from-black to-transparent">
                     <h2 className="text-4xl font-display font-black text-white italic uppercase tracking-tighter mb-2" style={{ textShadow: '0 0 20px rgba(0,0,0,0.8)' }}>
                         {match.fighterA.name}
