                    onClick={() => setMode('FIGHTER')}
                    className={`relative z-10 w-[140px] py-2 flex items-center justify-center gap-2 font-display font-bold text-sm tracking-wider uppercase transition-colors duration-300 ${mode === 'FIGHTER' ? 'text-black' : 'text-gray-500 hover:text-white'}`}
                >
                    <User size={16} /> Competidor
                </button>
            </div>
        </div>

        {/* Content Area */}
        <div className="animate-fade-in">
            {mode === 'BETTOR' ? (
                <BettingTerminal character={character} onUpdateJenny={updateJenny} />
            ) : (
                <CompetitorDashboard character={character} />
            )}
        </div>

      </main>
    </div>
  );
}

