interface Props {
  message: string;
  isActive: boolean;
  onDismiss: () => void;
}

export const ArenaNotification: React.FC<Props> = ({ message, isActive, onDismiss }) => {
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    if (isActive) {
      setVisible(true);
      const timer = setTimeout(() => {
        setVisible(false);
        setTimeout(onDismiss, 500); // Wait for exit animation
      }, 5000);
      return () => clearTimeout(timer);
    }
  }, [isActive, onDismiss]);

  if (!isActive && !visible) return null;

  return (
    <div 
      className={`fixed top-24 left-1/2 -translate-x-1/2 z-50 w-[90%] max-w-2xl pointer-events-none transition-all duration-500 ease-out
      ${visible ? 'opacity-100 translate-y-0 scale-100' : 'opacity-0 -translate-y-10 scale-90'}`}
    >
      <div className="bg-hxh-dark/95 border-2 border-hxh-green shadow-[0_0_50px_rgba(0,255,65,0.2)] text-center relative overflow-hidden clip-path-polygon p-1">

        {/* Animated Scanline */}
        <div className="absolute inset-0 bg-gradient-to-b from-transparent via-hxh-green/10 to-transparent animate-scanline pointer-events-none" />

        <div className="bg-black/80 p-6 flex flex-col items-center justify-center">
            <div className="flex items-center gap-2 text-hxh-green font-bold text-xs tracking-[0.3em] uppercase mb-2 animate-pulse">
                <Radio size={16} />
                Sinal Recebido: Discord Bot
            </div>

            <h2 className="text-3xl md:text-4xl font-display font-black text-white uppercase italic tracking-tighter text-shadow-green">
                {message}
            </h2>

            <div className="w-full h-1 bg-gradient-to-r from-transparent via-hxh-green to-transparent mt-4" />
        </div>
      </div>
    </div>
  );
};

