import React, { useState } from 'react';
import { INITIAL_CHARACTER } from './constants';
import { Character, DiscordUser } from './types';
import { CharacterHeader } from './components/CharacterHeader';
import { BettingTerminal } from './components/BettingTerminal';
import { CompetitorDashboard } from './components/CompetitorDashboard';
import { OtherCompetitors } from './components/OtherCompetitors';
import { DiscordLogin } from './components/DiscordLogin';
import { User, Dices, Users } from 'lucide-react';

function App() {
  const [character, setCharacter] = useState<Character>(INITIAL_CHARACTER);
  const [mode, setMode] = useState<'BETTOR' | 'FIGHTER' | 'OTHERS'>('BETTOR');
  const [discordUser, setDiscordUser] = useState<DiscordUser | null>(null);

  const updateJenny = (newAmount: number) => {
    setCharacter(prev => ({ ...prev, jenny: newAmount }));
  };

  if (!discordUser) {
      return <DiscordLogin onLogin={setDiscordUser} />;
  }

  return (
    <div className="min-h-screen pb-20 bg-[#050505] text-gray-200 selection:bg-hxh-green selection:text-black font-body">
      <CharacterHeader character={character} mode={mode === 'FIGHTER' ? 'FIGHTER' : 'BETTOR'} discordUser={discordUser} />

      <main className="max-w-7xl mx-auto mt-6 px-4">

        {/* NEW NAVIGATION LAYOUT */}
        <div className="flex flex-col items-center gap-4 mb-8">

            {/* Top: APOSTADOR (Bettor) */}
            <button 
                onClick={() => setMode('BETTOR')}
                className={`
                    relative w-full max-w-sm py-3 flex items-center justify-center gap-3 font-display font-bold text-lg tracking-widest uppercase transition-all duration-300 rounded-lg border-2 clip-path-polygon
                    ${mode === 'BETTOR' 
                        ? 'bg-hxh-green text-black border-hxh-green shadow-[0_0_20px_rgba(0,255,65,0.4)] scale-105' 
                        : 'bg-gray-900/50 text-gray-500 border-gray-700 hover:text-white hover:border-gray-500'}
                `}
            >
                <Dices size={24} />
                Área do Apostador
            </button>

            {/* Bottom Group: COMPETIDOR | OUTROS */}
            <div className="flex gap-4 w-full max-w-sm">
                <button 
                    onClick={() => setMode('FIGHTER')}
                    className={`
                        flex-1 py-2 flex items-center justify-center gap-2 font-display font-bold text-sm tracking-wider uppercase transition-all duration-300 rounded border clip-path-polygon
                        ${mode === 'FIGHTER' 
                            ? 'bg-hxh-blue text-black border-hxh-blue shadow-[0_0_15px_rgba(0,240,255,0.4)]' 
                            : 'bg-gray-900/50 text-gray-500 border-gray-800 hover:text-white hover:border-gray-600'}
                    `}
                >
                    <User size={16} /> Competidor
                </button>

                <button 
                    onClick={() => setMode('OTHERS')}
                    className={`
                        flex-1 py-2 flex items-center justify-center gap-2 font-display font-bold text-sm tracking-wider uppercase transition-all duration-300 rounded border clip-path-polygon
                        ${mode === 'OTHERS' 
                            ? 'bg-white text-black border-white shadow-[0_0_15px_rgba(255,255,255,0.4)]' 
                            : 'bg-gray-900/50 text-gray-500 border-gray-800 hover:text-white hover:border-gray-600'}
                    `}
                >
                    <Users size={16} /> Outros
                </button>
            </div>

        </div>

        {/* Content Area */}
        <div className="animate-fade-in">
            {mode === 'BETTOR' && (
                <BettingTerminal character={character} onUpdateJenny={updateJenny} />
            )}
            {mode === 'FIGHTER' && (
                <CompetitorDashboard character={character} />
            )}
            {mode === 'OTHERS' && (
                <OtherCompetitors />
            )}
        </div>

      </main>
    </div>
  );
}

export default App;

