    name: 'Chrollo Lucilfer',
    imageUrl: 'https://i.pinimg.com/736x/07/ee/66/07ee669d03426e95c1a79901584c6295.jpg',
    totalPool: 2500000
  },
  fighterB: {
    id: 'f2',
    name: 'Zeno Zoldyck',
    imageUrl: 'https://i.pinimg.com/736x/c5/42/4f/c5424f92d4b2488737233c091990c74c.jpg',
