                 </div>
             </div>
         )}
      </div>

      {/* DEV SIMULATION TOOL */}
      <div className="absolute bottom-[-40px] right-0 opacity-30 hover:opacity-100 transition-opacity">
          <button 
            onClick={handleSimulateCommand}
            className="flex items-center gap-2 bg-gray-900 text-white text-[10px] py-1 px-3 rounded-full border border-gray-700 hover:bg-[#5865F2] hover:border-[#5865F2]"
            title="Cicla: Iniciar Luta -> Encerrar Luta"
          >
              <Terminal size={12} />
              DEV: {match ? 'Encerrar Combate' : 'Simular Início'} (Discord Bot)
          </button>
      </div>

    </div>
    </>
  );
};

