import React, { useState } from 'react';
import { X, Smartphone, CreditCard, ShieldCheck, CheckCircle, ArrowRight, Wallet, Banknote } from 'lucide-react';
import { EXCHANGE_RATE, WITHDRAW_TAX_RATE } from '../constants';

interface Props {
  mode: 'DEPOSIT' | 'WITHDRAW';
  currentJenny: number;
  onClose: () => void;
  onConfirm: (amountJenny: number) => void;
}

export const PaymentModal: React.FC<Props> = ({ mode, currentJenny, onClose, onConfirm }) => {
  const [inputValue, setInputValue] = useState<string>('');
  const [processing, setProcessing] = useState(false);
  const [step, setStep] = useState<'INPUT' | 'PROCESSING' | 'SUCCESS'>('INPUT');

  // Logic Variables
  const amountBRL = parseFloat(inputValue) || 0;
  const depositJenny = Math.floor(amountBRL * EXCHANGE_RATE);

  // Withdraw Calc
  const withdrawGrossBRL = currentJenny / EXCHANGE_RATE;
  const withdrawTaxBRL = withdrawGrossBRL * WITHDRAW_TAX_RATE;
  const withdrawNetBRL = withdrawGrossBRL - withdrawTaxBRL;

  const handleConfirm = () => {
    setProcessing(true);
    setStep('PROCESSING');

    setTimeout(() => {
      setProcessing(false);
      setStep('SUCCESS');

      if (mode === 'DEPOSIT') {
          onConfirm(depositJenny);
      } else {
          // For withdraw, we pass negative number or handle in parent. 
          // Here we pass the amount to REMOVE from wallet.
          onConfirm(-currentJenny); // Removes all funds as per logic "Convert Hands" usually implies cashing out chips
      }
    }, 2000);
  };

  const isValidDeposit = mode === 'DEPOSIT' && amountBRL >= 0.50;
  const isValidWithdraw = mode === 'WITHDRAW' && currentJenny > 0;

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/90 backdrop-blur-sm" onClick={onClose} />

      <div className="relative bg-[#111] border border-gray-800 w-full max-w-md rounded-xl shadow-2xl overflow-hidden animate-fade-in flex flex-col">

        {/* Header */}
        <div className="bg-[#050505] p-4 flex justify-between items-center border-b border-gray-800">
            <div className="flex items-center gap-2">
                <Wallet className={mode === 'DEPOSIT' ? "text-hxh-green" : "text-hxh-accent"} size={20} />
                <h2 className="text-white font-display font-bold uppercase">
                    {mode === 'DEPOSIT' ? 'Banco de Kakin: Depósito' : 'Convert Hands: Saque'}
                </h2>
            </div>
            <button onClick={onClose} className="text-gray-500 hover:text-white transition-colors">
                <X size={20} />
            </button>
        </div>

        {/* Content */}
        <div className="p-6">

            {step === 'INPUT' && (
                <div className="space-y-6">

                    {/* DEPOSIT MODE */}
                    {mode === 'DEPOSIT' && (
                        <>
                            <div className="text-center mb-4">
                                <p className="text-gray-400 text-sm mb-2">Digite o valor em Reais (R$) para comprar Jenny.</p>
                                <p className="text-[10px] text-gray-500 uppercase">Mínimo: R$ 0,50</p>
                            </div>

                            <div className="bg-black border border-gray-700 rounded-lg p-4 flex items-center gap-2 focus-within:border-hxh-green transition-colors">
                                <span className="text-gray-400 font-bold">R$</span>
                                <input 
                                    type="number" 
                                    value={inputValue}
                                    onChange={(e) => setInputValue(e.target.value)}
                                    placeholder="0,00"
                                    min="0.50"
                                    step="0.10"
                                    className="bg-transparent text-white font-display font-bold text-2xl w-full outline-none"
                                />
                            </div>

                            <div className="flex items-center justify-center gap-4 text-gray-500">
                                <ArrowRight className="animate-pulse" />
                            </div>

                            <div className="bg-hxh-green/10 border border-hxh-green/30 rounded-lg p-4 text-center">
                                <span className="text-gray-400 text-xs uppercase block mb-1">Você Recebe</span>
                                <span className="text-hxh-green font-display font-black text-3xl">
                                    {depositJenny.toLocaleString()} J
                                </span>
                            </div>

                            <button 
                                onClick={handleConfirm}
                                disabled={!isValidDeposit}
                                className={`w-full py-4 rounded font-bold uppercase tracking-widest transition-all mt-4 flex items-center justify-center gap-2
                                    ${isValidDeposit 
                                        ? 'bg-hxh-green text-black hover:brightness-110 shadow-[0_0_20px_rgba(0,255,65,0.4)]' 
                                        : 'bg-gray-800 text-gray-500 cursor-not-allowed'}
                                `}
                            >
                                <CreditCard size={18} /> Confirmar Pagamento
                            </button>
                        </>
                    )}

                    {/* WITHDRAW MODE */}
                    {mode === 'WITHDRAW' && (
                        <>
                             <div className="text-center mb-4">
                                <p className="text-gray-400 text-sm">Converta suas fichas (Jenny) de volta para moeda real.</p>
                            </div>

                            <div className="space-y-3">
                                <div className="flex justify-between items-center bg-gray-900 p-3 rounded">
                                    <span className="text-gray-400 text-sm">Saldo Atual</span>
                                    <span className="text-white font-bold">{currentJenny.toLocaleString()} J</span>
                                </div>

                                <div className="flex justify-between items-center bg-gray-900 p-3 rounded">
                                    <span className="text-gray-400 text-sm">Conversão Bruta</span>
                                    <span className="text-white font-bold">R$ {withdrawGrossBRL.toFixed(2)}</span>
                                </div>

                                <div className="flex justify-between items-center bg-red-900/20 border border-red-900/50 p-3 rounded">
                                    <span className="text-red-400 text-sm">Taxa da Torre ({(WITHDRAW_TAX_RATE * 100)}%)</span>
                                    <span className="text-red-400 font-bold">- R$ {withdrawTaxBRL.toFixed(2)}</span>
                                </div>
                            </div>

                            <div className="bg-white/5 border border-white/10 rounded-lg p-4 text-center mt-2">
                                <span className="text-gray-400 text-xs uppercase block mb-1">Valor Líquido a Receber</span>
                                <span className="text-white font-display font-black text-3xl">
                                    R$ {withdrawNetBRL.toFixed(2)}
                                </span>
                            </div>

                            <button 
                                onClick={handleConfirm}
                                disabled={!isValidWithdraw}
                                className={`w-full py-4 rounded font-bold uppercase tracking-widest transition-all mt-4 flex items-center justify-center gap-2
                                    ${isValidWithdraw 
                                        ? 'bg-white text-black hover:bg-gray-200 shadow-[0_0_20px_rgba(255,255,255,0.4)]' 
                                        : 'bg-gray-800 text-gray-500 cursor-not-allowed'}
                                `}
                            >
                                <Banknote size={18} /> Realizar Saque
                            </button>
                        </>
                    )}
                </div>
            )}

            {step === 'PROCESSING' && (
                <div className="text-center py-12 flex flex-col items-center">
                    <ShieldCheck size={48} className="text-hxh-green animate-pulse mb-4" />
                    <h3 className="text-white font-display text-lg mb-2">Processando Transação...</h3>
                    <p className="text-gray-500 text-sm">Conectando ao sistema bancário global...</p>
                </div>
            )}

            {step === 'SUCCESS' && (
                <div className="text-center py-8">
                    <div className="flex justify-center mb-4">
                        <CheckCircle size={64} className={mode === 'DEPOSIT' ? "text-hxh-green animate-bounce" : "text-white animate-bounce"} />
                    </div>
                    <h2 className="text-2xl text-white font-display font-bold mb-2">
                        {mode === 'DEPOSIT' ? 'Pagamento Aprovado!' : 'Saque Solicitado!'}
                    </h2>
                    <p className="text-gray-400 mb-6 text-sm">
                        {mode === 'DEPOSIT' 
                            ? 'O saldo foi adicionado à sua carteira.' 
                            : 'O valor foi enviado para sua chave PIX cadastrada (Simulação).'}
                    </p>
                    <button 
                        onClick={onClose}
                        className="bg-gray-800 text-white hover:bg-gray-700 font-bold py-3 px-8 rounded uppercase tracking-widest transition-colors"
                    >
                        Fechar
                    </button>
                </div>
            )}

        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Character, LiveMatch, TowerFloorData, DiscordUser } from '../types';
import { TOWER_FLOOR_DATA, DISCORD_CONFIG, ADMIN_CONFIG, TOWER_TAX_RATE } from '../constants';
import { Swords, DollarSign, Lock, Unlock, Info, Radar, Activity, Wifi, Gavel, Wallet, Calculator, ArrowDownLeft, ArrowUpRight } from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { ArenaNotification } from './ArenaNotification';
import { PaymentModal } from './PaymentModal';

interface Props {
  character: Character;
  onUpdateJenny: (amount: number) => void;
  discordUser: DiscordUser | null;
}

// Initial Mock Match (can be null now)
const INITIAL_MATCH: LiveMatch | null = null;

export const BettingTerminal: React.FC<Props> = ({ character, onUpdateJenny, discordUser }) => {
  // State
  const [match, setMatch] = useState<LiveMatch | null>(INITIAL_MATCH);
  const [wager, setWager] = useState<number>(0);
  const [selectedFighterId, setSelectedFighterId] = useState<string | null>(null);

  // Notification State
  const [notification, setNotification] = useState<{ active: boolean, message: string }>({ active: false, message: '' });

  // Payment State
  const [paymentMode, setPaymentMode] = useState<'DEPOSIT' | 'WITHDRAW' | null>(null);

  // Judge Mode State
  const isJudge = discordUser && ADMIN_CONFIG.ADMIN_IDS.includes(discordUser.id);
  const [judgeForm, setJudgeForm] = useState({
    fighterAName: '',
    fighterBName: '',
    floor: 200
  });

  // Discord Bot / Socket Connection Effect
  useEffect(() => {
    // Lógica de Conexão com o Bot para RECEBER dados
    if (DISCORD_CONFIG.INBOUND_API_URL) {
        console.log(`Tentando conectar ao bot em: ${DISCORD_CONFIG.INBOUND_API_URL}`);
    }
  }, []);

  // HOUSE EDGE CALCULATION
  const totalPool = match ? match.fighterA.totalPool + match.fighterB.totalPool : 0;
  // The house takes a cut (e.g. 10%) from the total pool before calculating odds.
  const netPool = totalPool * (1 - TOWER_TAX_RATE);

  const oddsA = match && totalPool > 0 ? (netPool / Math.max(match.fighterA.totalPool, 1)) : 1.0;
  const oddsB = match && totalPool > 0 ? (netPool / Math.max(match.fighterB.totalPool, 1)) : 1.0;

  // Formatting Odds to never show less than 1.01x visually, though math might result in loss if pool is heavily skewed + tax
  const displayOddsA = Math.max(1.01, oddsA);
  const displayOddsB = Math.max(1.01, oddsB);

  // Find Floor Data
  const floorData: TowerFloorData | undefined = match ? TOWER_FLOOR_DATA.find(
      d => match.floor >= d.minFloor && match.floor <= d.maxFloor
  ) : undefined;

  const minBet = floorData ? floorData.betMin : 50;
  const maxBetLimit = floorData ? floorData.betMax : 1000000;
  const effectiveMaxBet = Math.min(character.jenny, maxBetLimit);

  // Initialize wager when match starts
  useEffect(() => {
     if (match && wager < minBet) setWager(Math.min(minBet, effectiveMaxBet));
  }, [match?.id]);

  // Simulate Live Betting (The "Hype" Factor)
  useEffect(() => {
    if (!match || match.status !== 'OPEN') return;

    const interval = setInterval(() => {
        setMatch(prev => {
            if (!prev) return null;
            const addToA = Math.random() > 0.4 ? Math.floor(Math.random() * 50000) : 0;
            const addToB = Math.random() > 0.4 ? Math.floor(Math.random() * 50000) : 0;
            return {
                ...prev,
                fighterA: { ...prev.fighterA, totalPool: prev.fighterA.totalPool + addToA },
                fighterB: { ...prev.fighterB, totalPool: prev.fighterB.totalPool + addToB }
            };
        });
    }, 2000);

    return () => clearInterval(interval);
  }, [match?.status]);

  // JUDGE ACTIONS
  const handleJudgeStartMatch = async () => {
    if (!judgeForm.fighterAName || !judgeForm.fighterBName) {
        alert("Preencha os nomes dos lutadores!");
        return;
    }

    const newMatch: LiveMatch = {
        id: `match_${Date.now()}`,
        floor: judgeForm.floor,
        status: 'OPEN',
        fighterA: {
            id: 'fa',
            name: judgeForm.fighterAName,
            imageUrl: 'https://placehold.co/400x600/1a1a1a/white?text=A', // Placeholder
            totalPool: 100000 // Seed pool
        },
        fighterB: {
            id: 'fb',
            name: judgeForm.fighterBName,
            imageUrl: 'https://placehold.co/400x600/1a1a1a/white?text=B', // Placeholder
            totalPool: 100000 // Seed pool
        }
    };

    setMatch(newMatch);
    setSelectedFighterId(null);
    setNotification({ active: true, message: `COMBATE SANCIONADO: ${newMatch.fighterA.name} VS ${newMatch.fighterB.name}` });

    // Send to Discord Webhook
    if (DISCORD_CONFIG.OUTBOUND_WEBHOOK_URL) {
        try {
            await fetch(DISCORD_CONFIG.OUTBOUND_WEBHOOK_URL, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    content: `📢 **ATENÇÃO ARENA!** Um novo combate foi sancionado pelo Juiz ${discordUser?.username}!`,
                    embeds: [{
                        title: "⚔️ COMBATE INICIADO",
                        description: `**${newMatch.fighterA.name}** VS **${newMatch.fighterB.name}**`,
                        color: 16711680, // Red
                        fields: [
                            { name: "Andar", value: `${newMatch.floor}`, inline: true },
                            { name: "Juiz", value: discordUser?.username || "Unknown", inline: true }
                        ],
                        footer: { text: "Façam suas apostas no terminal!" },
                        timestamp: new Date().toISOString()
                    }]
                })
            });
        } catch (e) {
            console.error("Webhook error", e);
        }
    }
  };

  const handleJudgeEndMatch = async () => {
      setMatch(prev => prev ? ({ ...prev, status: 'FINISHED' }) : null);
      setNotification({ active: true, message: "COMBATE ENCERRADO PELO JUIZ" });

      // Notify Discord
      if (DISCORD_CONFIG.OUTBOUND_WEBHOOK_URL) {
          try {
             await fetch(DISCORD_CONFIG.OUTBOUND_WEBHOOK_URL, {
                  method: 'POST',
                  headers: { 'Content-Type': 'application/json' },
                  body: JSON.stringify({
                      content: `🛑 **COMBATE ENCERRADO!** As apostas foram fechadas.`,
                  })
              });
          } catch(e) {}
      }

      setTimeout(() => {
          setMatch(null);
      }, 3000);
  };

  const handlePlaceBet = async () => {
      if (!match) return;
      if (wager > character.jenny) {
          alert("Fundos Insuficientes!");
          return;
      }
      if (wager < minBet) {
          alert(`Aposta mínima para este andar é ${minBet} J`);
          return;
      }

      if (!selectedFighterId) return;

      const isA = selectedFighterId === match.fighterA.id;
      const fighterName = isA ? match.fighterA.name : match.fighterB.name;
      const odds = isA ? displayOddsA : displayOddsB;

      // 1. Atualizar Estado Local
      onUpdateJenny(character.jenny - wager);

      setMatch(prev => {
        if (!prev) return null;
        return {
          ...prev,
          fighterA: { ...prev.fighterA, totalPool: prev.fighterA.totalPool + (isA ? wager : 0) },
          fighterB: { ...prev.fighterB, totalPool: prev.fighterB.totalPool + (!isA ? wager : 0) },
        }
      });

      // 2. Enviar para Discord via Webhook (Se configurado)
      if (DISCORD_CONFIG.OUTBOUND_WEBHOOK_URL) {
          try {
              await fetch(DISCORD_CONFIG.OUTBOUND_WEBHOOK_URL, {
                  method: 'POST',
                  headers: { 'Content-Type': 'application/json' },
                  body: JSON.stringify({
                      content: null,
                      embeds: [{
                          title: "🎰 Nova Aposta Registrada!",
                          color: 5763719, // Verde HxH aproximado
                          fields: [
                              { name: "Apostador", value: character.name, inline: true },
                              { name: "Lutador", value: fighterName, inline: true },
                              { name: "Valor", value: `${wager.toLocaleString()} J`, inline: true },
                              { name: "Odds", value: `${odds.toFixed(2)}x`, inline: true },
                              { name: "Andar", value: `${match.floor}`, inline: true }
                          ],
                          footer: { text: "Heaven's Gate Terminal" },
                          timestamp: new Date().toISOString()
                      }]
                  })
              });
          } catch (error) {
              console.error("Erro ao enviar webhook para Discord:", error);
          }
      }

      alert(`Aposta realizada em ${fighterName}!`);
      setSelectedFighterId(null);
  };

  const chartData = character.bettingHistory.map(bet => ({
      name: bet.fighterName,
      amount: bet.amount,
      result: bet.result,
      profit: bet.result === 'WIN' ? bet.amount : -bet.amount
  }));

  const handleTransaction = (amountJenny: number) => {
      onUpdateJenny(character.jenny + amountJenny);
  };

  return (
    <>
    {paymentMode && (
        <PaymentModal 
            mode={paymentMode} 
            currentJenny={character.jenny}
            onClose={() => setPaymentMode(null)} 
            onConfirm={handleTransaction} 
        />
    )}

    <ArenaNotification 
        message={notification.message} 
        isActive={notification.active} 
        onDismiss={() => setNotification(n => ({ ...n, active: false }))} 
    />

    <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 p-4 md:p-6 h-full animate-fade-in relative">

      {/* JUDGE PANEL (ONLY VISIBLE TO ADMINS) */}
      {isJudge && (
        <div className="lg:col-span-12 bg-yellow-900/20 border border-yellow-600/50 p-4 rounded-lg flex flex-col md:flex-row gap-4 items-center justify-between mb-4 shadow-[0_0_20px_rgba(234,179,8,0.1)]">
            <div className="flex items-center gap-3 text-yellow-500 font-display font-bold uppercase tracking-wider">
                <Gavel size={24} />
                Painel do Juiz de Andar
            </div>

            {!match ? (
                <div className="flex gap-2 w-full md:w-auto">
                    <input 
                        placeholder="Lutador A" 
                        className="bg-black/50 border border-yellow-800 text-white px-3 py-1 rounded text-sm outline-none focus:border-yellow-500"
                        value={judgeForm.fighterAName}
                        onChange={e => setJudgeForm(prev => ({...prev, fighterAName: e.target.value}))}
                    />
                    <span className="text-yellow-600 font-bold self-center">VS</span>
                    <input 
                        placeholder="Lutador B" 
                        className="bg-black/50 border border-yellow-800 text-white px-3 py-1 rounded text-sm outline-none focus:border-yellow-500"
                        value={judgeForm.fighterBName}
                        onChange={e => setJudgeForm(prev => ({...prev, fighterBName: e.target.value}))}
                    />
                    <select 
                        className="bg-black/50 border border-yellow-800 text-white px-3 py-1 rounded text-sm outline-none focus:border-yellow-500"
                        value={judgeForm.floor}
                        onChange={e => setJudgeForm(prev => ({...prev, floor: Number(e.target.value)}))}
                    >
                        {[50, 100, 200, 251].map(f => <option key={f} value={f}>Andar {f}</option>)}
                    </select>
                    <button 
                        onClick={handleJudgeStartMatch}
                        className="bg-yellow-600 hover:bg-yellow-500 text-black font-bold px-4 py-1 rounded text-sm transition-colors uppercase"
                    >
                        Sancionar Combate
                    </button>
                </div>
            ) : (
                <button 
                    onClick={handleJudgeEndMatch}
                    className="bg-red-600 hover:bg-red-500 text-white font-bold px-6 py-2 rounded transition-colors uppercase flex items-center gap-2"
                >
                    <Lock size={16} /> Encerrar Combate Oficial
                </button>
            )}
        </div>
      )}

      {/* LEFT COLUMN: HISTORY & WALLET & CURRENT MATCH STATUS (4 cols) */}
      <div className="lg:col-span-4 space-y-6 flex flex-col">

        {/* CURRENT MATCH CARD (Mini) */}
        <div className={`bg-hxh-panel border border-gray-800 p-4 rounded-lg relative overflow-hidden transition-all duration-500 ${match ? 'border-hxh-green/50 shadow-[0_0_15px_rgba(0,255,65,0.1)]' : 'opacity-70'}`}>
            <h3 className="text-xs font-bold uppercase tracking-widest text-gray-400 mb-2 flex items-center justify-between">
                <span>Status da Arena</span>
                <Wifi size={14} className={match ? "text-green-500" : "text-gray-600"} />
            </h3>

            {match ? (
                <div className="animate-fade-in">
                    <div className="flex justify-between items-center mb-2">
                         <span className="text-red-500 font-bold animate-pulse text-xs">● AO VIVO</span>
                         <span className="bg-gray-800 text-white text-[10px] px-2 py-0.5 rounded border border-gray-700">{match.floor}º ANDAR</span>
                    </div>
                    <div className="flex items-center justify-between text-white font-display font-bold text-sm">
                        <span className="truncate w-1/2">{match.fighterA.name}</span>
                        <span className="text-hxh-green mx-2 text-xs">VS</span>
                        <span className="truncate w-1/2 text-right">{match.fighterB.name}</span>
                    </div>
                    <div className="mt-2 w-full bg-gray-800 h-1 rounded-full overflow-hidden">
                        <div className="bg-hxh-green h-full animate-progress-indeterminate" />
                    </div>
                </div>
            ) : (
                <div className="flex flex-col items-center justify-center py-2 text-gray-500 gap-2">
                    <Radar className="animate-spin-slow text-gray-700" size={24} />
                    <span className="text-[10px] uppercase tracking-wider">Aguardando Sinal...</span>
                </div>
            )}
        </div>

        {/* Wallet */}
        <div className="bg-hxh-panel border border-hxh-green/30 p-6 rounded-lg shadow-[0_0_15px_rgba(0,255,65,0.1)] relative overflow-hidden group">
            <div className="absolute top-0 right-0 p-4 opacity-10">
                <DollarSign size={100} />
            </div>

            <div className="flex justify-between items-start mb-2 relative z-10">
                <h2 className="text-gray-400 text-xs uppercase font-bold tracking-widest flex items-center gap-2">
                    Saldo Disponível
                </h2>

                <div className="flex gap-2">
                    {/* Botão Depósito: Seta apontando para saldo (Baixo/Esquerda) */}
