                                 <div>
                                    <p className="text-gray-400 text-xs font-mono mb-1">ODDS (Net)</p>
                                    <p className="text-4xl font-bold text-hxh-accent">{displayOddsB.toFixed(2)}x</p>
                                 </div>
                             </div>
