                 </div>
             </div>
         )}
      </div>

    </div>
    </>
  );
};

export enum NenType {
  ENHANCEMENT = 'Enhancement',
  TRANSMUTATION = 'Transmutation',
  EMISSION = 'Emission',
  CONJURATION = 'Conjuration',
  MANIPULATION = 'Manipulation',
  SPECIALIZATION = 'Specialization',
}

export interface CharacterAttributes {
  strength: number;
  dexterity: number;
  constitution: number;
  intelligence: number;
  wisdom: number;
  charisma: number;
}

export interface BetRecord {
  id: string;
  fighterName: string;
  amount: number;
  result: 'WIN' | 'LOSS';
  timestamp: string;
}

export interface BattleRecord {
  id: string;
  opponentName: string;
  result: 'WIN' | 'LOSS';
  floor: number;
}

export interface FighterStats {
  currentFloor: number;
  totalWins: number;
  totalLosses: number;
  floorMasterWins: number; // 0-10
  floorMasterLosses: number; // 0-4
  hype: {
    totalBetsCount: number;
    totalJennyVolume: number;
  };
  battleHistory: BattleRecord[];
}

export interface Character {
  name: string;
  level: number;
  hunterStars: number;
  nenType: NenType;
  auraPoints: {
    current: number;
    max: number;
  };
  hitPoints: {
    current: number;
    max: number;
  };
  attributes: CharacterAttributes;

  // Wallet System
  jenny: number; // Saldo REAL (Sacável/Depositado/Lucro)
  trainingJenny: number; // Saldo de TREINO (Bloqueado)
  betsPlaced: number; // Contador para desbloqueio

  bettingHistory: BetRecord[];
  fighterStats: FighterStats;
}

export interface Competitor {
  id: string;
  name: string;
  imageUrl: string; 
  totalPool: number; 
}

export interface LiveMatch {
  id: string;
  floor: number;
  fighterA: Competitor;
  fighterB: Competitor;
  status: 'OPEN' | 'LOCKED' | 'FINISHED';
  winnerId?: string;
}

export interface DiscordWebhookConfig {
  url: string;
  username: string;
  enabled: boolean;
}

export interface BetScenario {
  id: string;
  title: string;
  description: string;
  difficulty: 'Easy' | 'Medium' | 'Hard' | 'Insane';
  winMultiplier: number;
  status: 'pending' | 'resolved';
}

export interface ArenaEvent {
  type: 'MATCH_START' | 'MATCH_END' | 'ODDS_UPDATE';
  message: string;
  payload?: any;
}

export interface TowerFloorData {
  minFloor: number;
  maxFloor: number;
  benefits: string;
  housingCost: number | null; // null represents "Não Liberada" or Free (0)
  housingLabel: string; // To display "Não Liberada", "300 $/dia", "0"
  prizeMoney: string | number; // String for "Lanche", number for values
  betMin: number;
  betAvg: number;
  betMax: number;
}

export interface DiscordUser {
  id: string;
  username: string;
  discriminator: string;
  avatar: string | null;
}

