    setStep('PROCESSING');

    // 4. Show Success Screen shortly after
    setTimeout(() => {
      setProcessing(false);
      setStep('SUCCESS');

      // 5. ACTUAL BALANCE UPDATE (Delayed by 2 minutes)
      setTimeout(() => {
          onConfirm(depositJenny);
          console.log("Saldo depositado após 2min.");
      }, 120000); // 120 seconds = 2 minutes

    }, 2000);
  };

  // Step 1 of Withdraw: Go to Method Selection
  const handleWithdrawStart = () => {
      setStep('WITHDRAW_METHOD');
  };

  // Step 2 of Withdraw: Select Method
  const handleSelectWithdrawMethod = (method: 'PIX' | 'BANK') => {
      setWithdrawMethod(method);
      setWithdrawDestination(''); // Reset input
      setStep('WITHDRAW_DETAILS');
  };

  // Step 3 of Withdraw: Final Confirm
  const handleWithdrawFinalConfirm = () => {
    if (!withdrawDestination) {
        alert("Por favor, preencha os dados de destino.");
        return;
    }

    setProcessing(true);
    setStep('PROCESSING');

    // Send Webhook for Withdraw Request
    if (DISCORD_CONFIG.OUTBOUND_WEBHOOK_URL) {
        try {
            fetch(DISCORD_CONFIG.OUTBOUND_WEBHOOK_URL, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
